export async function ensureInitialStore(storePath: string, fs: any) {
  try {
    await fs.access(storePath);
  } catch {
    await fs.writeFile(storePath, JSON.stringify(DEFAULT_STORE_DATA, null, 2), "utf8");
  }
}
